class Solution:
    def reverseParentheses(self, s: str) -> str:
        stack = []
        for c in s:
            if c == '(':
                stack.append(c)
            elif c == ')':
                temp = []
                while stack[-1] != '(':
                    temp.append(stack.pop())
                stack.pop() # pop '('
                stack.extend(temp)
            else:
                stack.append(c)
        return ''.join(stack)
```

